import React, { useState, useRef, useEffect } from 'react';
import { Menu, Send, Settings, LogOut } from 'lucide-react';
import ChatInterface from '../components/ChatInterface';
import Sidebar from '../components/Sidebar';
import AccountHealth from '../components/AccountHealth';

export default function ChatPage({ userProfile, setUserProfile, onExit }) {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const profile = userProfile || {
    accountBalance: 10000,
    dailyLossLimit: 200,
    dailyLossUsed: 0,
    strategy: {
      name: 'IFVG Trading',
      rules: 'Look for Invalid FVG setups on 15m/1h. Max 2% risk per trade. Max 3 trades per day.',
    },
  };

  const handleSendMessage = async (message) => {
    if (!message.trim()) return;

    // Add user message
    const userMsg = { role: 'user', content: message, id: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    // Simulate AI response (in production, call OpenAI API)
    setTimeout(() => {
      const aiResponse = generateCoachResponse(message, profile);
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: aiResponse,
        id: Date.now() + 1
      }]);
      setLoading(false);
    }, 1000);
  };

  const handleUpdateProfile = (updates) => {
    const newProfile = { ...profile, ...updates };
    setUserProfile(newProfile);
  };

  return (
    <div className="flex h-screen bg-dark-bg">
      {/* Sidebar */}
      <Sidebar 
        isOpen={sidebarOpen}
        onClose={() => setSidebarOpen(false)}
        profile={profile}
      />

      {/* Main Chat Area */}
      <div className="flex-1 flex flex-col">
        {/* Header */}
        <div className="border-b border-dark-border bg-dark-card px-4 py-3 flex items-center justify-between sticky top-0 z-40">
          <button
            onClick={() => setSidebarOpen(!sidebarOpen)}
            className="md:hidden p-2 hover:bg-dark-accent rounded"
          >
            <Menu size={20} />
          </button>

          <h1 className="text-lg font-bold">
            <span className="text-accent-green">TradeRisk</span> AI Coach
          </h1>

          <div className="flex gap-2">
            <button
              onClick={() => setShowSettings(!showSettings)}
              className="p-2 hover:bg-dark-accent rounded"
            >
              <Settings size={20} />
            </button>
            <button
              onClick={onExit}
              className="p-2 hover:bg-dark-accent rounded"
            >
              <LogOut size={20} />
            </button>
          </div>
        </div>

        <div className="flex-1 flex gap-4 overflow-hidden p-4">
          {/* Account Health (right sidebar on desktop) */}
          <div className="hidden lg:block w-80">
            <AccountHealth profile={profile} onUpdateProfile={handleUpdateProfile} />
          </div>

          {/* Chat */}
          <div className="flex-1 flex flex-col">
            <ChatInterface
              messages={messages}
              loading={loading}
              onSendMessage={handleSendMessage}
              profile={profile}
            />
          </div>
        </div>

        {/* Settings Modal */}
        {showSettings && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <SettingsModal profile={profile} onUpdateProfile={handleUpdateProfile} onClose={() => setShowSettings(false)} />
          </div>
        )}
      </div>
    </div>
  );
}

function SettingsModal({ profile, onUpdateProfile, onClose }) {
  const [formData, setFormData] = useState(profile);

  const handleSave = () => {
    onUpdateProfile(formData);
    onClose();
  };

  return (
    <div className="bg-dark-card border border-dark-border rounded-lg p-6 w-full max-w-md max-h-[80vh] overflow-y-auto">
      <h2 className="text-xl font-bold mb-4 text-accent-green">Settings</h2>

      <div className="space-y-4">
        <div>
          <label className="block text-sm font-medium mb-1">Account Balance ($)</label>
          <input
            type="number"
            value={formData.accountBalance}
            onChange={(e) => setFormData({ ...formData, accountBalance: parseFloat(e.target.value) })}
            className="w-full"
          />
        </div>

        <div>
          <label className="block text-sm font-medium mb-1">Daily Loss Limit ($)</label>
          <input
            type="number"
            value={formData.dailyLossLimit}
            onChange={(e) => setFormData({ ...formData, dailyLossLimit: parseFloat(e.target.value) })}
            className="w-full"
          />
        </div>

        <div>
          <label className="block text-sm font-medium mb-1">Strategy Name</label>
          <input
            type="text"
            value={formData.strategy.name}
            onChange={(e) => setFormData({
              ...formData,
              strategy: { ...formData.strategy, name: e.target.value }
            })}
            className="w-full"
          />
        </div>

        <div>
          <label className="block text-sm font-medium mb-1">Strategy Rules</label>
          <textarea
            value={formData.strategy.rules}
            onChange={(e) => setFormData({
              ...formData,
              strategy: { ...formData.strategy, rules: e.target.value }
            })}
            className="w-full h-24"
            placeholder="Define your trading strategy rules..."
          />
        </div>

        <div className="flex gap-2 pt-4">
          <button
            onClick={handleSave}
            className="flex-1 bg-accent-green text-dark-bg font-bold py-2 rounded hover:shadow-glow"
          >
            Save
          </button>
          <button
            onClick={onClose}
            className="flex-1 bg-dark-accent text-white font-bold py-2 rounded hover:bg-dark-border"
          >
            Cancel
          </button>
        </div>
      </div>
    </div>
  );
}

// Mock AI Response Generator
function generateCoachResponse(userMessage, profile) {
  const msg = userMessage.toLowerCase();

  // Strict trading coach logic
  const responses = {
    shouldTake: [
      `Let me evaluate this against your rules:\n\n📋 Your Strategy: ${profile.strategy.name}\n${profile.strategy.rules}\n\nDaily Loss Used: $${profile.dailyLossUsed}/$${profile.dailyLossLimit}\n\nBefore I give you the green light, I need more details:\n- What's your stop loss?\n- How much are you risking?\n- Does this setup match your strategy?\n\nGive me specifics and I'll tell you yes or no.`,
      `Hold up. 🛑\n\nI need more information to evaluate this properly:\n1. Stop loss distance (in ticks/pips)\n2. Risk amount or risk percentage\n3. Your entry level\n4. Does this match an IFVG setup or your defined strategy?\n\nDon't guess. Give me the numbers and I'll tell you if it's valid.`,
    ],
    overRisk: [
      `❌ DO NOT TAKE THIS TRADE.\n\nYou've already used $${profile.dailyLossUsed} of your $${profile.dailyLossLimit} daily limit. Taking another risk puts you over.\n\nDiscipline now = Account safety later. Stop trading for today.`,
      `⚠️ DANGER ZONE.\n\nYour daily loss limit is $${profile.dailyLossLimit}. You've used $${profile.dailyLossUsed}.\n\nThis trade violates your risk rules. The answer is NO. Close the charts if you have to.`,
    ],
    goodTrade: [
      `✅ VALID TRADE.\n\nThis fits your strategy and risk parameters:\n- Within your daily loss limit\n- Matches your ${profile.strategy.name} rules\n- Risk is appropriate for your account\n\nGo for it. But execute with precision.`,
      `✅ VALID.\n\nRisk: Appropriate ✓\nStrategy Match: Yes ✓\nDaily Limit: Safe ✓\n\nThis trade passes all checks. Execute if your setup is clean.`,
    ],
    default: [
      `I'm your trading coach, not a signal service.\n\nWhat I can do:\n✓ Evaluate if a trade fits YOUR rules\n✓ Check if you're over-risking\n✓ Help you stay disciplined\n\nTell me about a specific trade idea and I'll give you honest feedback.`,
      `Let me help you make better decisions.\n\nAsk me:\n• "Should I take this trade?"\n• "Is my daily loss limit hit?"\n• "Does this match my strategy?"\n\nI need specifics to give you real feedback.`,
    ]
  };

  if (msg.includes('should') || msg.includes('take') || msg.includes('entry')) {
    if (msg.includes('over') || msg.includes('limit') || msg.includes('lost') || msg.includes('down')) {
      return responses.overRisk[Math.floor(Math.random() * responses.overRisk.length)];
    }
    return responses.shouldTake[Math.floor(Math.random() * responses.shouldTake.length)];
  }

  if (msg.includes('valid') || msg.includes('good') || msg.includes('ok')) {
    return responses.goodTrade[Math.floor(Math.random() * responses.goodTrade.length)];
  }

  return responses.default[Math.floor(Math.random() * responses.default.length)];
}
